import React from "react";
import "../styles/Professionals.css"; // Ensure this path is correct

const professionals = [
  { id: 1, img: "/images/law.jpg", alt: "Professional 1" }
];

const Professionals = () => {
    return (
        <section className="professionals-section">
            <h2 className="section-title">OUR PROFESSIONALS</h2>
            <div className="professionals-grid">
                {professionals.map((pro) => (
                    <div key={pro.id} className="diamond">
                        {/* <img src={require(`./images/${law.img}`)} alt={pro.alt} /> */}
                    </div>
                ))}
            </div>
        </section>
    );
};

export default Professionals;
